import{_ as a,c as t,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Приложение: Справочные материалы | opencode-agent-skills","description":"Изучите приложение opencode-agent-skills, включая лучшие практики разработки навыков и справочник по API инструментам, овладейте техниками и стандартами написания качественных навыков.","frontmatter":{"title":"Приложение: Справочные материалы | opencode-agent-skills","sidebarTitle":"Справочник по разработке навыков","subtitle":"Приложение: Справочные материалы и стандарты разработки","description":"Изучите приложение opencode-agent-skills, включая лучшие практики разработки навыков и справочник по API инструментам, овладейте техниками и стандартами написания качественных навыков.","order":5},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/appendix/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/appendix/index.md"}'),o={name:"ru/joshuadavidthomas/opencode-agent-skills/appendix/index.md"};function s(r,e,d,n,c,h){return l(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="приложение" tabindex="-1">Приложение <a class="header-anchor" href="#приложение" aria-label="Permalink to &quot;Приложение&quot;">​</a></h1><p>Этот раздел предоставляет справочные материалы и стандарты разработки для OpenCode Agent Skills, помогая вам писать качественные навыки и быстро находить справочные данные по API интерфейсам.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Страница</th><th>Описание</th></tr></thead><tbody><tr><td><a href="./best-practices/">Лучшие практики разработки навыков</a></td><td>Освойте техники и стандарты написания качественных навыков, включая соглашения по именованию, написание описаний, организацию каталогов, использование скриптов и т.д.</td></tr><tr><td><a href="./api-reference/">Справочник по API инструментам</a></td><td>Просмотрите подробные параметры и возвращаемые значения всех доступных инструментов, включая <code>get_available_skills</code>, <code>read_skill_file</code>, <code>run_skill_script</code>, <code>use_skill</code></td></tr></tbody></table><h2 id="рекомендации-по-учебному-пути" tabindex="-1">Рекомендации по учебному пути <a class="header-anchor" href="#рекомендации-по-учебному-пути" aria-label="Permalink to &quot;Рекомендации по учебному пути&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Рекомендуемый порядок</p><ol><li><strong>Сначала изучите лучшие практики</strong> → Узнайте стандарты и техники разработки навыков, чтобы избежать распространённых ошибок</li><li><strong>Затем ознакомьтесь с API справочником</strong> → При возникновении проблем в процессе разработки, просмотрите конкретные параметры и возвращаемые значения</li></ol></div><p>Эти два раздела имеют разное назначение:</p><ul><li><strong>Лучшие практики</strong>: Подходит для предварительного ознакомления перед началом написания навыков, чтобы сформировать правильные привычки разработки</li><li><strong>Справочник API</strong>: Подходит как справочник для быстрого поиска конкретных деталей при необходимости</li></ul><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Рекомендуется предварительно завершить</p><p>Перед изучением этого раздела рекомендуется, чтобы вы:</p><ul><li>Завершили <a href="./../start/creating-your-first-skill/">Создание вашего первого навыка</a>, понимая базовую структуру навыков</li><li>Поняли <a href="./../platforms/skill-discovery-mechanism/">Механизм обнаружения навыков</a>, понимая, как плагин находит навыки</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела вы можете:</p><ul><li>Просмотреть <a href="./../faq/troubleshooting/">Устранение неполадок</a>, чтобы решить проблемы, возникающие при использовании</li><li>Узнать <a href="./../faq/security-considerations/">Соображения безопасности</a>, чтобы обеспечить безопасность навыков</li><li>Просмотреть <a href="./../changelog/">Историю версий</a>, чтобы понять эволюцию плагина и новые функции</li></ul>',13)])])}const _=a(o,[["render",s]]);export{u as __pageData,_ as default};
